311	void Testbed::reload_network_from_file(const fs::path& path) {
312		if (!path.empty()) {
313			fs::path candidate = find_network_config(path);
314			if (candidate.exists() || !m_network_config_path.exists()) {
315				// Store the path _argument_ in the member variable. E.g. for the base config,
316				// it'll store `base.json`, even though the loaded config will be
317				// config/<mode>/base.json. This has the benefit of switching to the
318				// appropriate config when switching modes.
319				m_network_config_path = path;
320			}
321		}
322	
323		// If the testbed mode hasn't been decided yet, don't load a network yet, but
324		// still keep track of the requested config (see above).
325		if (m_testbed_mode == ETestbedMode::None) {
326			return;
327		}
328	
329		fs::path full_network_config_path = find_network_config(m_network_config_path);
330		bool is_snapshot = equals_case_insensitive(full_network_config_path.extension(), "msgpack");
331	
332		if (!full_network_config_path.exists()) {
333			tlog::warning() << "Network " << (is_snapshot ? "snapshot" : "config") << " path '" << full_network_config_path
334							<< "' does not exist.";
335		} else {
336			m_network_config = load_network_config(full_network_config_path);
337		}
338	
339		// Reset training if we haven't loaded a snapshot of an already trained model, in which case, presumably the network
340		// configuration changed and the user is interested in seeing how it trains from scratch.
341		if (!is_snapshot) {
342			reset_network();
343		}
