353	void Testbed::load_file(const fs::path& path) {
354		if (!path.exists()) {
355			// If the path doesn't exist, but a network config can be resolved, load that.
356			if (equals_case_insensitive(path.extension(), "json") && find_network_config(path).exists()) {
357				reload_network_from_file(path);
358				return;
359			}
360	
361			tlog::error() << "File '" << path.str() << "' does not exist.";
362			return;
363		}
364	
365		if (equals_case_insensitive(path.extension(), "ingp") || equals_case_insensitive(path.extension(), "msgpack")) {
366			load_snapshot(path);
367			return;
368		}
369	
370		// If we get a json file, we need to parse it to determine its purpose.
371		if (equals_case_insensitive(path.extension(), "json")) {
372			json file;
373			{
374				std::ifstream f{native_string(path)};
375				file = json::parse(f, nullptr, true, true);
376			}
377	
378			// Snapshot in json format... inefficient, but technically supported.
379			if (file.contains("snapshot")) {
380				load_snapshot(path);
381				return;
382			}
383	
384			// Regular network config
385			if (file.contains("parent") || file.contains("network") || file.contains("encoding") || file.contains("loss") ||
386				file.contains("optimizer")) {
387				reload_network_from_file(path);
388				return;
389			}
390	
391			// Camera path
392			if (file.contains("path")) {
393				load_camera_path(path);
394				return;
395			}
396		}
397	
398		// If the dragged file isn't any of the above, assume that it's training data
399		try {
400			bool was_training_data_available = m_training_data_available;
401			load_training_data(path);
402	
403			if (!was_training_data_available) {
404				// If we previously didn't have any training data and only now dragged
405				// some into the window, it is very unlikely that the user doesn't
406				// want to immediately start training on that data. So: go for it.
407				m_train = true;
408			}
409		} catch (const std::runtime_error& e) { tlog::error() << "Failed to load training data: " << e.what(); }
410	}
